import type { ConceptCategory, ConceptLevel, ConceptNode } from '../types/concept'
import type { LocalizedStringArray, LocalizedText } from '../types/skill'

export const conceptCategories: ConceptCategory[] = ['positional', 'mechanical', 'strategic', 'defensive', 'offensive', 'training', 'safety', 'mindset']
export const conceptLevels: ConceptLevel[] = ['fundamental', 'intermediate', 'advanced']

const lt = (vi: string, en: string, fr: string): LocalizedText => ({ vi, en, fr })
const la = (vi: string[], en: string[], fr: string[]): LocalizedStringArray => ({ vi, en, fr })

type ConceptSeed = {
  id: string
  title: LocalizedText
  category: ConceptCategory
  level: ConceptLevel
  shortDefinition: LocalizedText
  whyItMatters: LocalizedText
  deepExplanation: LocalizedText
  beginnerView: LocalizedText
  advancedView: LocalizedText
  relatedSkillIds: string[]
  relatedConceptIds: string[]
  tags: string[]
}

const exampleFor = (seed: ConceptSeed): ConceptNode['ifThenExamples'] => [
  {
    if: lt(
      `Nếu bạn mất ${seed.title.vi} trong trao đổi.`,
      `If you lose ${seed.title.en} during the exchange.`,
      `Si vous perdez ${seed.title.fr} pendant l’échange.`,
    ),
    then: lt(
      'Dừng tăng tốc, lấy lại cấu trúc cơ thể gần nhất rồi mới tiếp tục kỹ thuật.',
      'Stop accelerating, recover the nearest body structure, then continue the technique.',
      'Arrêtez d’accélérer, récupérez la structure corporelle proche, puis continuez.',
    ),
    why: lt(
      'No-gi hiện đại phạt rất nhanh khi bạn cố thắng bằng sức sau khi mất cấu trúc.',
      'Modern no-gi punishes forceful continuation after structure is lost.',
      'Le no-gi moderne punit vite la force après perte de structure.',
    ),
    relatedSkillIds: seed.relatedSkillIds.slice(0, 2),
  },
  {
    if: lt(
      'Nếu đối thủ phản ứng đúng với hướng đầu tiên.',
      'If the opponent correctly answers your first line.',
      'Si l’adversaire répond correctement à votre première ligne.',
    ),
    then: lt(
      `Dùng ${seed.title.vi} để đổi sang nhánh an toàn hơn thay vì ép cùng một hướng.`,
      `Use ${seed.title.en} to switch to a safer branch instead of forcing the same line.`,
      `Utilisez ${seed.title.fr} pour passer à une branche plus sûre au lieu de forcer.`,
    ),
    why: lt(
      'Concept tốt biến phản ứng của đối thủ thành thông tin cho quyết định tiếp theo.',
      'A good concept turns the opponent’s reaction into information for the next decision.',
      'Un bon concept transforme la réaction adverse en information pour la décision suivante.',
    ),
    relatedSkillIds: seed.relatedSkillIds.slice(1, 4),
  },
]

const misunderstandingsFor = (seed: ConceptSeed): ConceptNode['commonMisunderstandings'] => [
  {
    misunderstanding: lt(
      `${seed.title.vi} là một mẹo kỹ thuật riêng lẻ.`,
      `${seed.title.en} is a single technical trick.`,
      `${seed.title.fr} est une astuce technique isolée.`,
    ),
    correction: lt(
      'Hãy xem nó như quy tắc quyết định xuất hiện trong nhiều vị trí khác nhau.',
      'Treat it as a decision rule that appears across many positions.',
      'Voyez-le comme une règle de décision présente dans plusieurs positions.',
    ),
  },
  {
    misunderstanding: lt(
      'Bạn chỉ cần hiểu khái niệm là tự động dùng được trong live roll.',
      'Understanding the concept automatically makes it work live.',
      'Comprendre le concept suffit pour l’utiliser en live.',
    ),
    correction: lt(
      'Khái niệm phải được gắn với body signal, cue ngắn và positional sparring.',
      'The concept needs body signals, short cues, and positional sparring.',
      'Le concept doit être lié à signaux corporels, cues courts et sparring positionnel.',
    ),
  },
]

const cueFor = (seed: ConceptSeed): LocalizedStringArray =>
  la(
    [
      `Gọi tên ${seed.title.vi} trước khi tăng lực.`,
      'Tìm body signal, không đoán bằng cảm giác chung.',
      'Nếu mất cấu trúc, reset một layer trước.',
      'Drill chậm, test bằng resistance tăng dần.',
    ],
    [
      `Name ${seed.title.en} before adding force.`,
      'Find the body signal instead of guessing generally.',
      'If structure is lost, reset one layer first.',
      'Drill slowly, then test with progressive resistance.',
    ],
    [
      `Nommez ${seed.title.fr} avant d’ajouter force.`,
      'Cherchez le signal corporel, pas une impression vague.',
      'Si la structure est perdue, reset une couche d’abord.',
      'Driller lentement, puis tester avec résistance progressive.',
    ],
  )

const concept = (seed: ConceptSeed): ConceptNode => ({
  ...seed,
  ifThenExamples: exampleFor(seed),
  commonMisunderstandings: misunderstandingsFor(seed),
  trainingCues: cueFor(seed),
})

